#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, t;
        scanf("%d %d", &n, &t);
        int li[n], ri[n];
        for (int i = 0; i < n; i++) {
            scanf("%d %d", &li[i], &ri[i]);
        }
        int maxCred = 0;
        for (double enter = 0; enter <= 1e9; enter += 0.1) {
            double leave = enter + t;
            int lessCool = 0, cooler = 0;
            for (int i = 0; i < n; i++) {
                if (enter < li[i] && leave > ri[i]) lessCool++;
                if (enter > li[i] && leave < ri[i]) cooler++;
            }
            maxCred = (maxCred > lessCool - cooler) ? maxCred : lessCool - cooler;
        }
        printf("%d\n", maxCred);
    }
    return 0;
}

