// COMPLETE, COMPILABLE Java code
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt(), t = sc.nextInt();
            int[] li = new int[n], ri = new int[n];
            for (int i = 0; i < n; i++) {
                li[i] = sc.nextInt();
                ri[i] = sc.nextInt();
            }
            int maxCred = 0;
            for (double enter = 0; enter <= 1e9; enter += 0.1) {
                double leave = enter + t;
                int lessCool = 0, cooler = 0;
                for (int i = 0; i < n; i++) {
                    if (enter < li[i] && leave > ri[i]) lessCool++;
                    if (enter > li[i] && leave < ri[i]) cooler++;
                }
                maxCred = Math.max(maxCred, lessCool - cooler);
            }
            System.out.println(maxCred);
        }
    }
}

